import{_ as t,o as i,c as a,ag as n}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"Interactive Aliase | Dotfiles (DE)","titleTemplate":":title","description":"Shell-Aliase mit interaktiven Prompts vor destruktiven Operationen wie rm, mv und cp. Versehentliches Loeschen von Dateien verhindern.","frontmatter":{"title":"Interactive Aliase | Dotfiles","description":"Shell-Aliase mit interaktiven Prompts vor destruktiven Operationen wie rm, mv und cp. Versehentliches Loeschen von Dateien verhindern.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Interactive Aliase preview","canonical":"/de/aliases/interactive/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Interactive Aliase","pageType":"docs","schemaType":"WebPage","metaTitle":"Interactive Aliase - Dotfiles (DE)","permalink":"/de/aliases/interactive/","sidebar":true,"meta":[{"name":"keywords","content":"interactive aliase, shell sicherheit, rm bestaetigung, cp interaktiv, mv prompt, dotfiles, bash aliase"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Interactive Aliase - Dotfiles"},{"name":"twitter:description","content":"Shell-Aliase mit interaktiven Prompts vor destruktiven Operationen wie rm, mv und cp."},{"name":"og:title","content":"Interactive Aliase - Dotfiles"},{"name":"og:description","content":"Shell-Aliase mit interaktiven Prompts vor destruktiven Operationen wie rm, mv und cp."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"de_DE"}]},"headers":[],"relativePath":"de/aliases/interactive/index.md","filePath":"de/aliases/interactive/index.md","lastUpdated":1773010926000}'),r={name:"de/aliases/interactive/index.md"};function l(s,e,d,o,c,h){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="interactive-aliase" tabindex="-1">Interactive Aliase <a class="header-anchor" href="#interactive-aliase" aria-label="Permalink to &quot;Interactive Aliase&quot;">​</a></h1><p>Sichere Shell-Befehle mit Bestaetigungsprompts vor destruktiven Operationen.</p><h2 id="uebersicht" tabindex="-1">Uebersicht <a class="header-anchor" href="#uebersicht" aria-label="Permalink to &quot;Uebersicht&quot;">​</a></h2><p>Interactive-Aliase fuegen Bestaetigungsprompts zu gaengigen Shell-Befehlen hinzu, die Dateien dauerhaft aendern oder loeschen koennen. In <code>interactive.aliases.sh</code> definiert und automatisch von Chezmoi geladen, helfen diese Aliase versehentlichen Datenverlust zu verhindern, indem sie Benutzerbestaetigung vor dem Ausfuehren potenziell destruktiver Operationen erfordern.</p><h2 id="referenz" tabindex="-1">Referenz <a class="header-anchor" href="#referenz" aria-label="Permalink to &quot;Referenz&quot;">​</a></h2><h3 id="dateioperationen" tabindex="-1">Dateioperationen <a class="header-anchor" href="#dateioperationen" aria-label="Permalink to &quot;Dateioperationen&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cp</code></td><td style="text-align:left;">Dateien und Verzeichnisse interaktiv mit ausfuehrlicher Ausgabe kopieren. Fragt vor dem Ueberschreiben.</td></tr><tr><td style="text-align:left;"><code>mv</code></td><td style="text-align:left;">Dateien interaktiv mit ausfuehrlicher Ausgabe verschieben oder umbenennen. Fragt vor dem Ueberschreiben.</td></tr><tr><td style="text-align:left;"><code>ln</code></td><td style="text-align:left;">Symbolische Links interaktiv mit ausfuehrlicher Ausgabe erstellen. Fragt vor dem Ueberschreiben.</td></tr></tbody></table><h3 id="dateiloeschung" tabindex="-1">Dateiloeschung <a class="header-anchor" href="#dateiloeschung" aria-label="Permalink to &quot;Dateiloeschung&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>rm</code></td><td style="text-align:left;">Dateien oder Verzeichnisse interaktiv mit ausfuehrlicher Ausgabe entfernen. Fragt vor jedem Loeschen.</td></tr><tr><td style="text-align:left;"><code>del</code></td><td style="text-align:left;">Dateien oder Verzeichnisse interaktiv und rekursiv mit ausfuehrlicher Ausgabe entfernen. Fragt vor jedem Loeschen.</td></tr><tr><td style="text-align:left;"><code>zap</code></td><td style="text-align:left;">Alias fuer <code>rm</code>. Entfernt Dateien oder Verzeichnisse interaktiv mit ausfuehrlicher Ausgabe.</td></tr></tbody></table><h3 id="papierkorb-verwaltung" tabindex="-1">Papierkorb-Verwaltung <a class="header-anchor" href="#papierkorb-verwaltung" aria-label="Permalink to &quot;Papierkorb-Verwaltung&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>bin</code></td><td style="text-align:left;">Alle Dateien im Papierkorb-Verzeichnis (<code>~/.Trash</code>) erzwungen und rekursiv entfernen.</td></tr></tbody></table><h3 id="berechtigungen-und-hilfsprogramme" tabindex="-1">Berechtigungen und Hilfsprogramme <a class="header-anchor" href="#berechtigungen-und-hilfsprogramme" aria-label="Permalink to &quot;Berechtigungen und Hilfsprogramme&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod</code></td><td style="text-align:left;">Datei- oder Verzeichnisberechtigungen mit ausfuehrlicher Ausgabe aendern.</td></tr><tr><td style="text-align:left;"><code>chown</code></td><td style="text-align:left;">Besitzer und Gruppe von Dateien oder Verzeichnissen mit ausfuehrlicher Ausgabe aendern.</td></tr><tr><td style="text-align:left;"><code>diff</code></td><td style="text-align:left;">Dateien vergleichen und Unterschiede im Unified-Format anzeigen.</td></tr><tr><td style="text-align:left;"><code>grep</code></td><td style="text-align:left;">Nach einem Muster in Dateien oder Ausgabe suchen, Zeilennummern anzeigen, Gross-/Kleinschreibung ignorieren.</td></tr><tr><td style="text-align:left;"><code>mkdir</code></td><td style="text-align:left;">Neues Verzeichnis mit Elternverzeichnissen nach Bedarf und ausfuehrlicher Ausgabe erstellen.</td></tr></tbody></table>',13)])])}const m=t(r,[["render",l]]);export{g as __pageData,m as default};
